<?php
namespace App\Modules\Hr\Recruitment\Actions;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Recruitment\Models\HrApplication;use App\Modules\Hr\Recruitment\Models\HrJobOffer;use Carbon\Carbon;
class ManageJobOfferAction{public function __construct(private HrAuditService $audit){}public function create(HrApplication $application,array $data):HrJobOffer{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.make_offer'),403);abort_unless($application->legal_entity_id===app(TenantContext::class)->getId()&&$application->current_stage==='offer'&&$application->status==='active',422);$start=Carbon::parse($data['proposed_start_date']??null);$expires=Carbon::parse($data['expires_on']??null);abort_if((float)($data['gross_salary']??0)<=0||$expires->isPast(),422);$offer=HrJobOffer::updateOrCreate(['application_id'=>$application->id],['legal_entity_id'=>$application->legal_entity_id,'gross_salary'=>$data['gross_salary'],'currency'=>$data['currency']??'TRY','proposed_start_date'=>$start,'expires_on'=>$expires,'status'=>'pending_approval','created_by'=>auth()->id()]);$this->audit->log('recruitment_offer_created',$offer,null,['gross_salary'=>'[MASKED]']);return $offer;}public function approve(HrJobOffer $offer,string $note):HrJobOffer{abort_unless(auth()->user()?->hasHrPermission('hr.recruitment.approve'),403);abort_unless($offer->legal_entity_id===app(TenantContext::class)->getId()&&$offer->status==='pending_approval',422);abort_if(blank($note),422);$offer->update(['status'=>'approved','approval_note'=>trim($note),'approved_by'=>auth()->id(),'approved_at'=>now()]);$this->audit->log('recruitment_offer_approved',$offer);return $offer->fresh();}}
